from dataclasses import dataclass, field


@dataclass(frozen=True)
class Station:
    code: str          # đài code / URL slug / file name, e.g. 'xshcm'
    name: str          # display name, e.g. 'Xổ số TPHCM'
    region: str        # region page slug: 'xsmn' (South) | 'xsmt' (Central)
    weekdays: frozenset[int] = field(default_factory=frozenset)  # 0=Mon .. 6=Sun


# Full list of Central (xsmt) and Northern-excluded provinces.
# Generated by scanning https://xoso.com.vn/{region}-{date}.html over a full week.
# `weekdays` is only used to skip dates a station certainly does not draw when
# back-filling; the region page itself is the source of truth for which đài drew.
