STATION_BY_CODE: dict[str, Station] = {s.code: s for s in STATIONS}

REGIONS: tuple[str, ...] = ('xsmn', 'xsmt')


def stations_of(region: str) -> list[Station]:
    return [s for s in STATIONS if s.region == region]
